17	// Stable refusal codes returned when a review turn cannot proceed. These are
18	// part of the external contract — operators triage on these literal strings.
19	const (
20		RefusalCodePromptBudgetExceeded = "PROMPT_BUDGET_EXCEEDED"
21		RefusalCodeCostCapExceeded      = "COST_CAP_EXCEEDED"
22		RefusalCodeReviewerUnavailable  = "REVIEWER_UNAVAILABLE"
23	)
24	
25	// ReviewRefusalBody is the structured JSON body attached to all review turn
26	// refusals. Code is one of the RefusalCode* constants above.
27	type ReviewRefusalBody struct {
28		Code           string `json:"code"`
29		Message        string `json:"message"`
30		Retryable      bool   `json:"retryable"`
31		OperatorAction string `json:"operator_action"`
32	}
33	
34	// MarshalRefusalJSON returns the JSON encoding of a ReviewRefusalBody.
35	func MarshalRefusalJSON(code, message, operatorAction string, retryable bool) (string, error) {
36		b := ReviewRefusalBody{
37			Code:           code,
38			Message:        message,
39			Retryable:      retryable,
40			OperatorAction: operatorAction,
41		}
42		data, err := json.Marshal(b)
43		if err != nil {
44			return "", err
45		}
46		return string(data), nil
47	}
48	
49	// ReviewCostCapExceededError is returned by AppendTurn when adding the turn's
50	// cost to the session's accumulated cost would exceed MaxBillableUSD.
51	type ReviewCostCapExceededError struct {
52		SessionID   string
53		CurrentCost float64
54		TurnCost    float64
55		MaxUSD      float64
56	}
57	
58	func (e *ReviewCostCapExceededError) Error() string {
59		return fmt.Sprintf(
60			"COST_CAP_EXCEEDED: session %s current cost $%.4f + turn cost $%.4f exceeds max_billable_usd $%.4f",
61			e.SessionID, e.CurrentCost, e.TurnCost, e.MaxUSD,
62		)
63	}
64	
65	// RefusalBody returns the structured JSON refusal body for this error.
66	func (e *ReviewCostCapExceededError) RefusalBody() ReviewRefusalBody {
67		return ReviewRefusalBody{
68			Code:           RefusalCodeCostCapExceeded,
69			Message:        e.Error(),
70			Retryable:      false,
71			OperatorAction: "raise max_billable_usd for the review session or create a new session",
72		}
73	}
74	
75	// ReviewerUnavailableError is returned when a review turn is attempted on a
76	// session that is in a terminal state and cannot accept new reviewer turns.
77	type ReviewerUnavailableError struct {
78		SessionID string
79		Status    string
80	}
81	
82	func (e *ReviewerUnavailableError) Error() string {
83		return fmt.Sprintf(
84			"REVIEWER_UNAVAILABLE: session %s has status %q and cannot accept new review turns",
85			e.SessionID, e.Status,
86		)
87	}
88	
89	// RefusalBody returns the structured JSON refusal body for this error.
90	func (e *ReviewerUnavailableError) RefusalBody() ReviewRefusalBody {
91		return ReviewRefusalBody{
92			Code:           RefusalCodeReviewerUnavailable,
93			Message:        e.Error(),
94			Retryable:      false,
95			OperatorAction: "open a new review session to continue",
96		}
97	}
