99	const (
100		reviewSessionsDirName = "reviews"
101		reviewManifestName    = "manifest.json"
102		reviewTurnsName       = "turns.jsonl"
103		reviewAttachmentsDir  = "attachments"
104	)
105	
106	// ReviewSession is the server-side review state machine persisted under
107	// .ddx/reviews/<session-id>/ for Story 16 and review mutations.
108	//
109	// Story 16 on-disk contract:
110	//   - manifest.json stores the session metadata only: id, artifact refs,
111	//     rubric/template/prompt refs, status, and billing limits.
112	//   - turns.jsonl is append-only JSONL. Each non-empty line is one ReviewTurn
113	//     record with actor, content, cost_usd, and created_at.
114	//   - attachments/ stores any binary sidecar files for the session.
115	//
116	// The manifest is written when a session is created. Turns are appended
117	// without rewriting prior lines so the review transcript remains durable and
118	// streamable.
119	type ReviewSession struct {
120		ID             string       `json:"id"`
121		ArtifactID     string       `json:"artifact_id"`
122		ArtifactSHA    string       `json:"artifact_sha"`
123		ArtifactGitRev string       `json:"artifact_git_rev"`
124		SystemRubric   string       `json:"system_rubric"`
125		TemplateRef    string       `json:"template_ref"`
126		PromptRef      string       `json:"prompt_ref"`
127		Status         string       `json:"status"`
128		Turns          []ReviewTurn `json:"turns,omitempty"`
129		CostUSD        float64      `json:"cost_usd"`
130		MaxBillableUSD float64      `json:"max_billable_usd"`
131	}
132	
133	// ReviewTurn is one append-only transcript entry in turns.jsonl.
134	type ReviewTurn struct {
135		Actor     string    `json:"actor"`
136		Content   string    `json:"content"`
137		CostUSD   float64   `json:"cost_usd"`
138		CreatedAt time.Time `json:"created_at"`
139	}
140	
141	type reviewSessionManifest struct {
142		ID             string  `json:"id"`
143		ArtifactID     string  `json:"artifact_id"`
144		ArtifactSHA    string  `json:"artifact_sha"`
145		ArtifactGitRev string  `json:"artifact_git_rev"`
146		SystemRubric   string  `json:"system_rubric"`
147		TemplateRef    string  `json:"template_ref"`
148		PromptRef      string  `json:"prompt_ref"`
149		Status         string  `json:"status"`
150		CostUSD        float64 `json:"cost_usd"`
151		MaxBillableUSD float64 `json:"max_billable_usd"`
152	}
153	
154	// ReviewSessionStore persists review sessions under .ddx/reviews/.
155	type ReviewSessionStore struct {
156		projectRoot string
157		mu          sync.Mutex
158	}
159	
160	// NewReviewSessionStore constructs a store rooted at projectRoot.
161	func NewReviewSessionStore(projectRoot string) *ReviewSessionStore {
162		return &ReviewSessionStore{projectRoot: projectRoot}
163	}
164	
165	// Create initializes the session directory, writes manifest.json, seeds
166	// turns.jsonl, and creates attachments/.
167	func (s *ReviewSessionStore) Create(session ReviewSession) error {
168		if s == nil {
169			return errors.New("review session store: nil store")
170		}
171		root, err := s.sessionRoot(session.ID)
172		if err != nil {
173			return err
174		}
175	
176		s.mu.Lock()
177		defer s.mu.Unlock()
178	
179		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
180			return fmt.Errorf("review session: mkdir attachments: %w", err)
181		}
182		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
183			return err
184		}
185		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
186			return fmt.Errorf("review session: seed turns: %w", err)
187		}
188		return nil
189	}
190	
191	// AppendTurn appends a single transcript entry to turns.jsonl. It enforces
192	// MaxBillableUSD: if the session has a non-zero budget cap and the accumulated
193	// cost plus this turn's cost would exceed it, AppendTurn returns a
194	// *ReviewCostCapExceededError without writing the turn. On success the
195	// manifest's CostUSD accumulator is updated to reflect the new total.
196	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
197		if s == nil {
198			return errors.New("review session store: nil store")
199		}
200		root, err := s.sessionRoot(sessionID)
201		if err != nil {
202			return err
203		}
204	
205		s.mu.Lock()
206		defer s.mu.Unlock()
207	
208		if err := os.MkdirAll(root, 0o755); err != nil {
209			return fmt.Errorf("review session: mkdir session: %w", err)
210		}
211	
212		// Load the manifest to check the cost cap and read the current accumulated
213		// cost. If the manifest does not exist yet (session created without Create),
214		// proceed without enforcement.
215		manifestPath := filepath.Join(root, reviewManifestName)
216		var manifest *reviewSessionManifest
217		if data, readErr := os.ReadFile(manifestPath); readErr == nil {
218			var m reviewSessionManifest
219			if jsonErr := json.Unmarshal(data, &m); jsonErr == nil {
220				manifest = &m
221			}
222		}
223	
224		if manifest != nil && manifest.MaxBillableUSD > 0 {
225			if manifest.CostUSD+turn.CostUSD > manifest.MaxBillableUSD {
226				return &ReviewCostCapExceededError{
227					SessionID:   sessionID,
228					CurrentCost: manifest.CostUSD,
229					TurnCost:    turn.CostUSD,
230					MaxUSD:      manifest.MaxBillableUSD,
231				}
232			}
233		}
234	
235		if turn.CreatedAt.IsZero() {
236			turn.CreatedAt = time.Now().UTC()
237		}
238		path := filepath.Join(root, reviewTurnsName)
239		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
240		if err != nil {
241			return fmt.Errorf("review session: open turns: %w", err)
242		}
243		defer f.Close()
244		if err := json.NewEncoder(f).Encode(turn); err != nil {
245			return fmt.Errorf("review session: encode turn: %w", err)
246		}
247	
248		// Update the manifest's CostUSD accumulator so the next AppendTurn sees
249		// the correct running total.
250		if manifest != nil {
251			manifest.CostUSD += turn.CostUSD
252			_ = writeJSONFile(manifestPath, *manifest)
253		}
254	
255		return nil
256	}
257	
258	// Load reads the manifest plus append-only transcript back into memory.
259	func (s *ReviewSessionStore) Load(sessionID string) (*ReviewSession, error) {
260		if s == nil {
261			return nil, errors.New("review session store: nil store")
262		}
263		root, err := s.sessionRoot(sessionID)
264		if err != nil {
265			return nil, err
266		}
267	
268		data, err := os.ReadFile(filepath.Join(root, reviewManifestName))
269		if err != nil {
270			return nil, fmt.Errorf("review session: read manifest: %w", err)
271		}
272		var manifest reviewSessionManifest
273		if err := json.Unmarshal(data, &manifest); err != nil {
274			return nil, fmt.Errorf("review session: parse manifest: %w", err)
275		}
276		session := &ReviewSession{
277			ID:             manifest.ID,
278			ArtifactID:     manifest.ArtifactID,
279			ArtifactSHA:    manifest.ArtifactSHA,
280			ArtifactGitRev: manifest.ArtifactGitRev,
281			SystemRubric:   manifest.SystemRubric,
282			TemplateRef:    manifest.TemplateRef,
283			PromptRef:      manifest.PromptRef,
284			Status:         manifest.Status,
285			CostUSD:        manifest.CostUSD,
286			MaxBillableUSD: manifest.MaxBillableUSD,
287		}
288	
289		turnsPath := filepath.Join(root, reviewTurnsName)
290		f, err := os.Open(turnsPath)
291		if err != nil {
292			if os.IsNotExist(err) {
293				return session, nil
294			}
295			return nil, fmt.Errorf("review session: read turns: %w", err)
296		}
297		defer f.Close()
298	
299		scanner := bufio.NewScanner(f)
300		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
301		for scanner.Scan() {
302			line := strings.TrimSpace(scanner.Text())
303			if line == "" {
304				continue
305			}
306			var turn ReviewTurn
307			if err := json.Unmarshal([]byte(line), &turn); err != nil {
308				return nil, fmt.Errorf("review session: parse turn: %w", err)
309			}
310			session.Turns = append(session.Turns, turn)
311		}
312		if err := scanner.Err(); err != nil {
313			return nil, fmt.Errorf("review session: scan turns: %w", err)
314		}
315		return session, nil
316	}
317	
318	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
319		if s == nil {
320			return "", errors.New("review session store: nil store")
321		}
322		if s.projectRoot == "" {
323			return "", errors.New("review session store: empty project root")
324		}
325		if sessionID == "" {
326			return "", errors.New("review session store: empty session id")
327		}
328		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
329			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
330		}
331		return ddxroot.JoinProject(s.projectRoot, reviewSessionsDirName, sessionID), nil
332	}
333	
334	func reviewSessionManifestFrom(session ReviewSession) reviewSessionManifest {
335		return reviewSessionManifest{
336			ID:             session.ID,
337			ArtifactID:     session.ArtifactID,
338			ArtifactSHA:    session.ArtifactSHA,
339			ArtifactGitRev: session.ArtifactGitRev,
340			SystemRubric:   session.SystemRubric,
341			TemplateRef:    session.TemplateRef,
342			PromptRef:      session.PromptRef,
343			Status:         session.Status,
344			CostUSD:        session.CostUSD,
345			MaxBillableUSD: session.MaxBillableUSD,
346		}
347	}
348	
349	func writeJSONFile(path string, v any) error {
350		data, err := json.MarshalIndent(v, "", "  ")
351		if err != nil {
352			return fmt.Errorf("review session: marshal %s: %w", path, err)
353		}
354		data = append(data, '\n')
355		if err := os.WriteFile(path, data, 0o644); err != nil {
356			return fmt.Errorf("review session: write %s: %w", path, err)
357		}
358		return nil
359	}
