1	package graphql
2	
3	import (
4		"context"
5		"crypto/rand"
6		"encoding/hex"
7		"fmt"
8		"sync"
9		"time"
10	)
11	
12	// Review session lifecycle status values exposed via the GraphQL ReviewSession
13	// type. Stored as the manifest status on disk and broadcast verbatim on
14	// reviewSessionEvents.
15	const (
16		ReviewSessionStatusActive    = "active"
17		ReviewSessionStatusCancelled = "cancelled"
18		ReviewSessionStatusCompleted = "completed"
19	)
20	
21	// Review event kinds emitted on the reviewSessionEvents subscription. Delta
22	// chunks (kind=delta) are optional; the final-message event (kind=final) is
23	// required so subscribers can reconstruct the reviewer turn even when no
24	// upstream streaming is available.
25	const (
26		ReviewSessionEventKindDelta = "delta"
27		ReviewSessionEventKindFinal = "final"
28	)
29	
30	// ReviewSessionService is the production interface satisfied by the server
31	// package's review session store + dispatcher pair. The resolver depends only
32	// on this interface so tests can inject a fake implementation without spinning
33	// up the on-disk store.
34	//
35	// When the resolver is constructed with a nil ReviewSessions service the
36	// in-memory default (NewInMemoryReviewSessionService) is used. The default
37	// records turns and broadcasts a synthetic reviewer reply on Respond so the
38	// reviewSessionEvents subscription delivers the required final-message event
39	// without depending on the (separately-tracked) dispatcher bead.
40	type ReviewSessionService interface {
41		Start(ctx context.Context, input ReviewSessionStartInput) (*ReviewSession, error)
42		Respond(ctx context.Context, sessionID string, turn ReviewTurnInput) (*ReviewSession, error)
43		Cancel(ctx context.Context, sessionID string) (bool, error)
44		Subscribe(sessionID string) (<-chan *ReviewSessionEvent, func())
45	}
46	
47	// inMemoryReviewSessionService is the default ReviewSessionService used when
48	// the server has not wired a production implementation. It keeps sessions in
49	// memory and produces a deterministic synthetic reviewer turn on each
50	// Respond call so the subscription path is end-to-end testable from the
51	// GraphQL layer alone.
52	type inMemoryReviewSessionService struct {
53		mu       sync.Mutex
54		sessions map[string]*ReviewSession
55		subs     map[string][]chan *ReviewSessionEvent
56	}
57	
58	// NewInMemoryReviewSessionService returns the default service backing the
59	// review session mutations and subscription when the resolver has no wired
60	// production implementation.
61	func NewInMemoryReviewSessionService() ReviewSessionService {
62		return &inMemoryReviewSessionService{
63			sessions: map[string]*ReviewSession{},
64			subs:     map[string][]chan *ReviewSessionEvent{},
65		}
66	}
67	
68	func (s *inMemoryReviewSessionService) Start(_ context.Context, input ReviewSessionStartInput) (*ReviewSession, error) {
69		if input.ArtifactID == "" {
70			return nil, fmt.Errorf("reviewSessionStart: artifactId is required")
71		}
72		if input.ArtifactSha == "" {
73			return nil, fmt.Errorf("reviewSessionStart: artifactSha is required")
74		}
75	
76		id := ""
77		if input.SessionID != nil {
78			id = *input.SessionID
79		}
80		if id == "" {
81			var err error
82			id, err = newReviewSessionID()
83			if err != nil {
84				return nil, err
85			}
86		}
87	
88		s.mu.Lock()
89		defer s.mu.Unlock()
90		if _, exists := s.sessions[id]; exists {
91			return nil, fmt.Errorf("reviewSessionStart: session %q already exists", id)
92		}
93	
94		session := &ReviewSession{
95			ID:          id,
96			ArtifactID:  input.ArtifactID,
97			ArtifactSha: input.ArtifactSha,
98			TemplateRef: input.TemplateRef,
99			PromptRef:   input.PromptRef,
100			Status:      ReviewSessionStatusActive,
101			Turns:       []*ReviewTurn{},
102		}
103		if input.MaxBillableUsd != nil {
104			session.MaxBillableUsd = *input.MaxBillableUsd
105		}
106		s.sessions[id] = session
107		return cloneReviewSession(session), nil
108	}
109	
110	func (s *inMemoryReviewSessionService) Respond(_ context.Context, sessionID string, turn ReviewTurnInput) (*ReviewSession, error) {
111		if sessionID == "" {
112			return nil, fmt.Errorf("reviewSessionRespond: sessionId is required")
113		}
114		if turn.Content == "" {
115			return nil, fmt.Errorf("reviewSessionRespond: turn content is required")
116		}
117	
118		s.mu.Lock()
119		session, ok := s.sessions[sessionID]
120		if !ok {
121			s.mu.Unlock()
122			return nil, fmt.Errorf("reviewSessionRespond: session %q not found", sessionID)
123		}
124		if session.Status != ReviewSessionStatusActive {
125			s.mu.Unlock()
126			return nil, fmt.Errorf("reviewSessionRespond: session %q has status %q", sessionID, session.Status)
127		}
128	
129		now := time.Now().UTC().Format(time.RFC3339Nano)
130		userTurn := &ReviewTurn{
131			Actor:     "user",
132			Content:   turn.Content,
133			CostUsd:   0,
134			CreatedAt: now,
135		}
136		reviewerTurn := &ReviewTurn{
137			Actor:     "reviewer",
138			Content:   "review pending dispatcher integration",
139			CostUsd:   0,
140			CreatedAt: now,
141		}
142		session.Turns = append(session.Turns, userTurn, reviewerTurn)
143		snapshot := cloneReviewSession(session)
144		s.mu.Unlock()
145	
146		s.publish(sessionID, &ReviewSessionEvent{
147			SessionID: sessionID,
148			Kind:      ReviewSessionEventKindFinal,
149			Content:   reviewerTurn.Content,
150			CostUsd:   reviewerTurn.CostUsd,
151			Timestamp: now,
152		})
153	
154		return snapshot, nil
155	}
