255	// ReviewSessionEvents is the resolver for the reviewSessionEvents subscription.
256	//
257	// The subscription guarantees at least one final-message event per reviewer
258	// turn. Streaming deltas (kind=delta) are optional — subscribers that want to
259	// render incremental output may consume them but are not required to.
260	func (r *subscriptionResolver) ReviewSessionEvents(ctx context.Context, sessionID string) (<-chan *ReviewSessionEvent, error) {
261		src, unsub := r.reviewSessionService().Subscribe(sessionID)
262		out := make(chan *ReviewSessionEvent, 16)
263		go func() {
264			defer unsub()
265			defer close(out)
266			for {
267				select {
268				case <-ctx.Done():
269					return
270				case ev, ok := <-src:
271					if !ok {
272						return
273					}
274					select {
275					case out <- ev:
276					case <-ctx.Done():
277						return
278					}
279				}
280			}
281		}()
282		return out, nil
283	}
