158	// symbol describes one newly-added top-level function or method declaration
159	// from the worktree side of the diff.
160	type symbol struct {
161		AbsFile    string // absolute path
162		Line       int    // declaration line in HEAD
163		Symbol     string // "Func" or "(*T).Method" or "T.Method"
164		Annotation string // bead-id named in `// wiring:pending <bead-id>`, else ""
165	}
166	
167	// newSymbols returns top-level FuncDecls present in the worktree (HEAD)
168	// version of each changed file but absent from the DIFF_BASE version,
169	// keyed by (file, qualified symbol name). Test files are skipped.
170	func newSymbols(projectRoot, diffBase string, files []string) ([]symbol, error) {
171		var out []symbol
172		for _, rel := range files {
173			abs := filepath.Join(projectRoot, rel)
174			newSrc, err := os.ReadFile(abs)
175			if err != nil {
176				// File deleted in HEAD — nothing to add.
177				continue
178			}
179			oldSrc, _ := gitShow(projectRoot, diffBase, rel) // empty on add
180			oldDecls := declSet(oldSrc, rel)
181			fset := token.NewFileSet()
182			f, err := parser.ParseFile(fset, abs, newSrc, parser.ParseComments)
183			if err != nil {
184				return nil, fmt.Errorf("parse %s: %w", rel, err)
185			}
186			for _, decl := range f.Decls {
187				fd, ok := decl.(*ast.FuncDecl)
188				if !ok {
189					continue
190				}
191				qn := qualName(fd)
192				if _, existed := oldDecls[qn]; existed {
193					continue
194				}
195				pos := fset.Position(fd.Pos())
196				out = append(out, symbol{
197					AbsFile:    abs,
198					Line:       pos.Line,
199					Symbol:     qn,
200					Annotation: extractPendingBead(fd),
201				})
202			}
203		}
204		return out, nil
205	}
206	
207	func declSet(src []byte, displayName string) map[string]struct{} {
208		out := map[string]struct{}{}
209		if len(src) == 0 {
210			return out
211		}
212		fset := token.NewFileSet()
213		f, err := parser.ParseFile(fset, displayName, src, 0)
214		if err != nil {
215			return out
216		}
217		for _, decl := range f.Decls {
218			if fd, ok := decl.(*ast.FuncDecl); ok {
219				out[qualName(fd)] = struct{}{}
220			}
221		}
222		return out
223	}
224	
225	// qualName returns deadcode-style qualified name: "Func" for plain functions,
226	// "T.Method" for value-receiver methods, "(*T).Method" for pointer-receiver.
227	func qualName(fd *ast.FuncDecl) string {
228		if fd.Recv == nil || len(fd.Recv.List) == 0 {
229			return fd.Name.Name
230		}
231		recv := fd.Recv.List[0].Type
232		switch t := recv.(type) {
233		case *ast.StarExpr:
234			if id, ok := t.X.(*ast.Ident); ok {
235				return fmt.Sprintf("(*%s).%s", id.Name, fd.Name.Name)
236			}
237		case *ast.Ident:
238			return fmt.Sprintf("%s.%s", t.Name, fd.Name.Name)
239		case *ast.IndexExpr:
240			if id, ok := t.X.(*ast.Ident); ok {
241				return fmt.Sprintf("%s.%s", id.Name, fd.Name.Name)
242			}
243		case *ast.IndexListExpr:
244			if id, ok := t.X.(*ast.Ident); ok {
245				return fmt.Sprintf("%s.%s", id.Name, fd.Name.Name)
246			}
247		}
248		return fd.Name.Name
249	}
