251	// extractPendingBead scans the doc comment block immediately preceding a
252	// FuncDecl for `// wiring:pending <bead-id>`. Returns the bead id or "".
253	func extractPendingBead(fd *ast.FuncDecl) string {
254		if fd.Doc == nil {
255			return ""
256		}
257		for _, c := range fd.Doc.List {
258			txt := strings.TrimSpace(strings.TrimPrefix(c.Text, "//"))
259			txt = strings.TrimSpace(strings.TrimPrefix(txt, "/*"))
260			txt = strings.TrimSuffix(txt, "*/")
261			txt = strings.TrimSpace(txt)
262			const tag = "wiring:pending"
263			if strings.HasPrefix(txt, tag) {
264				rest := strings.TrimSpace(strings.TrimPrefix(txt, tag))
265				rest = strings.Fields(rest + " ")[0]
266				return rest
267			}
268		}
269		return ""

