288	func splitNonEmptyLines(s string) []string {
289		lines := make([]string, 0)
290		for _, line := range strings.Split(s, "\n") {
291			if strings.TrimSpace(line) == "" {
292				continue
293			}
294			lines = append(lines, line)
295		}
296		return lines
297	}
