package server

import "time"

// ReviewSession is the in-memory representation of a review session as
// consumed by the review prompt assembler. Fields are also serialized to
// session state on disk by callers that persist sessions; this package no
// longer ships the on-disk store directly.
type ReviewSession struct {
	ID             string       `json:"id"`
	ArtifactID     string       `json:"artifact_id"`
	ArtifactSHA    string       `json:"artifact_sha"`
	ArtifactGitRev string       `json:"artifact_git_rev"`
	SystemRubric   string       `json:"system_rubric"`
	TemplateRef    string       `json:"template_ref"`
	PromptRef      string       `json:"prompt_ref"`
	Status         string       `json:"status"`
	Turns          []ReviewTurn `json:"turns,omitempty"`
	CostUSD        float64      `json:"cost_usd"`
	MaxBillableUSD float64      `json:"max_billable_usd"`
}

// ReviewTurn is one transcript entry in a review session.
type ReviewTurn struct {
	Actor     string    `json:"actor"`
	Content   string    `json:"content"`
	CostUSD   float64   `json:"cost_usd"`
	CreatedAt time.Time `json:"created_at"`
}
